// --- HMAC Utility for tamper prevention ---

class HmacUtil {

    private static final String HMAC_ALGORITHM = "HmacSHA256";

    // In production, load from a secure vault / HSM per client
    private static final ConcurrentHashMap<String, String> CLIENT_SECRETS = new ConcurrentHashMap<>();

    static {
        // Pre-shared secrets per B2B client - in production use secure key management
        CLIENT_SECRETS.put("CLIENT_001", "c2VjcmV0S2V5Rm9yQ2xpZW50MDAxVmVyeUxvbmdBbmRTZWN1cmU=");
        CLIENT_SECRETS.put("CLIENT_002", "c2VjcmV0S2V5Rm9yQ2xpZW50MDAyVmVyeUxvbmdBbmRTZWN1cmU=");
    }

    public static String getClientSecret(String clientId) {
        return CLIENT_SECRETS.get(clientId);
    }

    public static String computeHmac(String data, String secret) {
        try {
            Mac mac = Mac.getInstance(HMAC_ALGORITHM);
            SecretKeySpec keySpec = new SecretKeySpec(
                    Base64.getDecoder().decode(secret), HMAC_ALGORITHM);
            mac.init(keySpec);
            byte[] hmacBytes = mac.doFinal(data.getBytes(StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hmacBytes);
        } catch (NoSuchAlgorithmException | InvalidKeyException e) {
            throw new RuntimeException("HMAC computation failed", e);
        }
    }

    public static boolean verifyHmac(String data, String expectedHmac, String secret) {
        String computedHmac = computeHmac(data, secret);
        // Constant-time comparison to prevent timing attacks
        return constantTimeEquals(computedHmac, expectedHmac);
    }

    private static boolean constantTimeEquals(String a, String b) {
        if (a == null || b == null) return false;
        byte[] aBytes = a.getBytes(StandardCharsets.UTF_8);
        byte[] bBytes = b.getBytes(StandardCharsets.UTF_8);
        if (aBytes.length != bBytes.length) return false;
        int result = 0;
        for (int i = 0; i < aBytes.length; i++) {
            result |= aBytes[i] ^ bBytes[i];
        }
        return result == 0;
    }

    /**
     * Build canonical string from order parameters for HMAC signing.
     * This ensures all critical fields are covered by the signature.
     */
    public static String buildCanonicalString(OrderRequest request) {
        StringBuilder sb = new StringBuilder();
        sb.append("orderId=").append(request.getOrderId()).append("&");
        sb.append("clientId=").append(request.getClientId()).append("&");
        sb.append("timestamp=").append(request.getTimestamp()).append("&");
        sb.append("nonce=").append(request.getNonce()).append("&");
        sb.append("items=");

        List<OrderItem> items = request.getItems();
        // Sort items by itemId for canonical ordering
        List<OrderItem> sortedItems = new ArrayList<>(items);
        sortedItems.sort((a, b2) -> a.getItemId().compareTo(b2.getItemId()));

        for (int i = 0; i < sortedItems.size(); i++) {
            OrderItem item = sortedItems.get(i);
            if (i > 0) sb.append(";");
            sb.append(item.getItemId()).append(",");
            sb.append(item.getUnitPrice().toPlainString()).append(",");
            sb.append(item.getQuantity());
        }
        return sb.toString();
    }
}

// --- Nonce and Replay Protection ---

class ReplayProtectionService {

    // In production, use a distributed cache like Redis with TTL
    private static final ConcurrentHashMap<String, Long> USED_NONCES = new ConcurrentHashMap<>();
    private static final long MAX_TIMESTAMP_DRIFT_SECONDS = 300; // 5 minutes

    public static synchronized boolean isReplayAttack(String nonce, String timestamp) {
        // Check timestamp freshness
        try {
            long requestTime = Long.parseLong(timestamp);
            long currentTime = Instant.now().getEpochSecond();
            long drift = Math.abs(currentTime - requestTime);

            if (drift > MAX_TIMESTAMP_DRIFT_SECONDS) {
                return true; // Request too old or too far in the future
            }
        } catch (NumberFormatException e) {
            return true; // Invalid timestamp
        }

        // Check nonce uniqueness
        if (USED_NONCES.containsKey(nonce)) {
            return true; // Nonce already used - replay attack
        }

        // Store nonce
        USED_NONCES.put(nonce, Instant.now().getEpochSecond());

        // Cleanup old nonces (in production, use TTL-based cache)
        cleanupOldNonces();

        return false;
    }

    private static void cleanupOldNonces() {
        long cutoff = Instant.now().getEpochSecond() - (MAX_TIMESTAMP_DRIFT_SECONDS * 2);
        USED_NONCES.entrySet().removeIf(entry -> entry.getValue() < cutoff);
    }
}

// --- Input Validation ---

class InputValidator {

    private static final Pattern SAFE_ID_PATTERN = Pattern.compile("^[A-Za-z0-9_-]{1,64}$");
    private static final Pattern SAFE_NAME_PATTERN = Pattern.compile("^[A-Za-z0-9 _.,'-]{1,256}$");
    private static final int MAX_ITEMS_PER_ORDER = 1000;
    private static final int MAX_QUANTITY_PER_ITEM = 100000;
    private static final BigDecimal MAX_UNIT_PRICE = new BigDecimal("9999999.99");
    private static final BigDecimal MIN_UNIT_PRICE = new BigDecimal("0.01");

    public static void validateOrderRequest(OrderRequest request) {
        if (request == null) {
            throw new WebServiceException("Order request cannot be null");
        }

        validateRequiredField(request.getOrderId(), "orderId");
        validateRequiredField(request.getClientId(), "clientId");
        validateRequiredField(request.getTimestamp(), "timestamp");
        validateRequiredField(request.getNonce(), "nonce");
        validateRequiredField(request.getHmacSignature(), "hmacSignature");

        if (!SAFE_ID_PATTERN.matcher(request.getOrderId()).matches()) {
            throw new WebServiceException("Invalid orderId format");
        }
        if (!SAFE_ID_PATTERN.matcher(request.getClientId()).matches()) {
            throw new WebServiceException("Invalid clientId format");
        }
        if (!SAFE_ID_PATTERN.matcher(request.getNonce()).matches()) {
            throw new WebServiceException("Invalid nonce format");
        }

        if (request.getItems() == null || request.getItems().isEmpty()) {
            throw new WebServiceException("Order must contain at least one item");
        }
        if (request.getItems().size() > MAX_ITEMS_PER_ORDER) {
            throw new WebServiceException("Order exceeds maximum number of items: " + MAX_ITEMS_PER_ORDER);
        }

        for (OrderItem item : request.getItems()) {
            validateOrderItem(item);
        }
    }

    private static void validateOrderItem(OrderItem item) {
        if (item == null) {
            throw new WebServiceException("Order item cannot be null");
        }

        validateRequiredField(item.getItemId(), "itemId");
        if (!SAFE_ID_PATTERN.matcher(item.getItemId()).matches()) {
            throw new WebServiceException("Invalid itemId format: " + item.getItemId());
        }

        if (item.getItemName() != null && !SAFE_NAME_PATTERN.matcher(item.getItemName()).matches()) {
            throw new WebServiceException("Invalid itemName format");
        }

        if (item.getUnitPrice() == null) {
            throw new WebServiceException("Unit price is required for item: " + item.getItemId());
        }
        if (item.getUnitPrice().compareTo(MIN_UNIT_PRICE) < 0) {
            throw new WebServiceException("Unit price below minimum for item: " + item.getItemId());
        }
        if (item.getUnitPrice().compareTo(MAX_UNIT_PRICE) > 0) {
            throw new WebServiceException("Unit price exceeds maximum for item: " + item.getItemId());
        }
        if (item.getUnitPrice().scale() > 2) {
            throw new WebServiceException("Unit price has too many decimal places for item: " + item.getItemId());
        }

        if (item.getQuantity() <= 0) {
            throw new WebServiceException("Quantity must be positive for item: " + item.getItemId());
        }
        if (item.getQuantity() > MAX_QUANTITY_PER_ITEM) {
            throw new WebServiceException("Quantity exceeds maximum for item: " + item.getItemId());
        }
    }

    private static void validateRequiredField(String value, String fieldName) {
        if (value == null || value.trim().isEmpty()) {
            throw new WebServiceException("Required field missing: " + fieldName);
        }
    }
}

// --- Server-side price verification ---

class PriceCatalogService {

    // In production, this would query a database
    private static final ConcurrentHashMap<String, BigDecimal> CATALOG_PRICES = new ConcurrentHashMap<>();

    static {
        CATALOG_PRICES.put("ITEM_001", new BigDecimal("29.99"));
        CATALOG_PRICES.put("ITEM_002", new BigDecimal("49.99"));
        CATALOG_PRICES.put("ITEM_003", new BigDecimal("9.99"));
        CATALOG_PRICES.put("ITEM_004", new BigDecimal("199.99"));
        CATALOG_PRICES.put("ITEM_005", new BigDecimal("14.50"));
    }

    /**
     * Verify that submitted prices match server-side catalog prices.
     * This prevents price tampering even if HMAC is somehow compromised.
     */
    public static void verifyPrices(List<OrderItem> items) {
        for (OrderItem item : items) {
            BigDecimal catalogPrice = CATALOG_PRICES.get(item.getItemId());
            if (catalogPrice == null) {
                throw new WebServiceException("Unknown item: " + item.getItemId());
            }
            if (catalogPrice.compareTo(item.getUnitPrice()) != 0) {
                throw new WebServiceException(
                        "Price mismatch for item " + item.getItemId() +
                                ": submitted=" + item.getUnitPrice().toPlainString() +
                                ", catalog=" + catalogPrice.toPlainString());
            }
        }
    }

    public static BigDecimal getCatalogPrice(String itemId) {
        return CATALOG_PRICES.get(itemId);
    }
}

// --- SOAP Message Handler for WS-Security style validation ---

class SecuritySOAPHandler implements SOAPHandler<SOAPMessageContext> {

    @Override
    public Set<QName> getHeaders() {
        return Collections.emptySet();
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (!isOutbound) {
            // Inbound message - validate SOAP structure
            try {
                SOAPMessage message = context.getMessage();
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPBody body = envelope.getBody();

                if (body == null) {
                    throw new WebServiceException("SOAP body is missing");
                }

                // Check for SOAP injection / XXE patterns in the raw message
                // JAX-WS by default should handle XXE, but we add defense in depth
                if (body.hasFault()) {
                    throw new WebServiceException("Unexpected SOAP fault in request");
                }

            } catch (SOAPException e) {
                throw new WebServiceException("Invalid SOAP message structure: " + e.getMessage());
            }
        }
        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // No cleanup needed
    }
}

// --- Main Web Service ---

@WebService(
        name = "OrderProcessingService",
        serviceName = "OrderProcessingService",
        targetNamespace = "http://b2b.example.com/orders"
)
@HandlerChain(file = "handler-chain.xml")
class OrderProcessingServiceImpl {

    /**
     * Process a B2B order with full tamper protection.
     *
     * Security measures:
     * 1. HMAC signature verification on all order parameters (prevents tampering)
     * 2. Nonce + timestamp for replay attack prevention
     * 3. Server-side price verification against catalog
     * 4. Input validation and sanitization
     * 5. BigDecimal for precise monetary calculations
     * 6. Constant-time HMAC comparison (prevents timing attacks)
     */
    @WebMethod(operationName = "processOrder")
    @WebResult(name = "OrderResponse")
    public OrderResponse processOrder(
            @WebParam(name = "OrderRequest") OrderRequest orderRequest) {

        try {
            // Step 1: Input validation
            InputValidator.validateOrderRequest(orderRequest);

            // Step 2: Verify client exists and get shared secret
            String clientSecret = HmacUtil.getClientSecret(orderRequest.getClientId());
            if (clientSecret == null) {
                return createErrorResponse(orderRequest.getOrderId(),
                        "UNAUTHORIZED", "Unknown client: " + orderRequest.getClientId());
            }

            // Step 3: Replay attack prevention
            if (ReplayProtectionService.isReplayAttack(orderRequest.getNonce(), orderRequest.getTimestamp())) {
                return createErrorResponse(orderRequest.getOrderId(),
                        "REJECTED", "Request rejected: possible replay attack or expired timestamp");
            }

            // Step 4: HMAC signature verification - prevents parameter tampering
            String canonicalString = HmacUtil.buildCanonicalString(orderRequest);
            if (!HmacUtil.verifyHmac(canonicalString, orderRequest.getHmacSignature(), clientSecret)) {
                return createErrorResponse(orderRequest.getOrderId(),
                        "TAMPERED", "HMAC signature verification failed - possible tampering detected");
            }

            // Step 5: Server-side price verification against catalog
            // Even with valid HMAC, we verify prices server-side as defense in depth
            PriceCatalogService.verifyPrices(orderRequest.getItems());

            // Step 6: Calculate total using server-side catalog prices (not client-submitted prices)
            BigDecimal totalPrice = calculateTotalFromCatalog(orderRequest.getItems());

            // Step 7: Process the order (business logic)
            String processingResult = executeOrderProcessing(orderRequest, totalPrice);

            // Step 8: Build signed response
            OrderResponse response = new OrderResponse(
                    orderRequest.getOrderId(),
                    "CONFIRMED",
                    totalPrice,
                    processingResult
            );

            // Sign the response so client can verify it wasn't tampered with in transit
            String responseCanonical = buildResponseCanonical(response);
            response.setResponseSignature(HmacUtil.computeHmac(responseCanonical, clientSecret));

            return response;

        } catch (WebServiceException e) {
            return createErrorResponse(
                    orderRequest != null ? orderRequest.getOrderId() : "UNKNOWN",
                    "ERROR",
                    e.getMessage()
            );
        } catch (Exception e) {
            // Don't leak internal details
            return createErrorResponse(
                    orderRequest != null ? orderRequest.getOrderId() : "UNKNOWN",
                    "INTERNAL_ERROR",
                    "An internal error occurred processing the order"
            );
        }
    }

    /**
     * Retrieve current catalog price for an item.
     * Clients should call this to get current prices before submitting orders.
     */
    @WebMethod(operationName = "getItemPrice")
    @WebResult(name = "ItemPrice")
    public BigDecimal getItemPrice(
            @WebParam(name = "itemId") String itemId,
            @WebParam(name = "clientId") String clientId) {

        if (itemId == null || clientId == null) {
            throw new WebServiceException("itemId and clientId are required");
        }

        // Verify client
        if (HmacUtil.getClientSecret(clientId) == null) {
            throw new WebServiceException("Unknown client");
        }

        BigDecimal price = PriceCatalogService.getCatalogPrice(itemId);
        if (price == null) {
            throw new WebServiceException("Unknown item: " + itemId);
        }
        return price;
    }

    /**
     * Calculate total using server-side catalog prices, not client-submitted values.
     * This is the authoritative price calculation.
     */
    private BigDecimal calculateTotalFromCatalog(List<OrderItem> items) {
        BigDecimal total = BigDecimal.ZERO;

        for (OrderItem item : items) {
            BigDecimal catalogPrice = PriceCatalogService.getCatalogPrice(item.getItemId());
            if (catalogPrice == null) {
                throw new WebServiceException("Item not found in catalog: " + item.getItemId());
            }

            BigDecimal lineTotal = catalogPrice.multiply(BigDecimal.valueOf(item.getQuantity()));
            total = total.add(lineTotal);
        }

        return total.setScale(2, RoundingMode.HALF_UP);
    }

    private String executeOrderProcessing(OrderRequest request, BigDecimal totalPrice) {
        // In production: persist to database, trigger fulfillment, etc.
        StringBuilder sb = new StringBuilder();
        sb.append("Order ").append(request.getOrderId())
                .append(" for client ").append(request.getClientId())
                .append(" processed successfully. ")
                .append(request.getItems().size()).append(" item(s), ")
                .append("Total: $").append(totalPrice.toPlainString());
        return sb.toString();
    }

    private String buildResponseCanonical(OrderResponse response) {
        return "orderId=" + response.getOrderId() +
                "&status=" + response.getStatus() +
                "&totalPrice=" + response.getTotalPrice().toPlainString() +
                "&message=" + response.getMessage();
    }

    private OrderResponse createErrorResponse(String orderId, String status, String message) {
        return new OrderResponse(orderId, status, BigDecimal.ZERO, message);
    }
}

// --- Client helper for building signed requests ---

class OrderRequestBuilder {

    /**
     * Helper for B2B clients to build properly signed order requests.
     */
    public static OrderRequest buildSignedRequest(
            String orderId, String clientId, String clientSecret, List<OrderItem> items) {

        OrderRequest request = new OrderRequest();
        request.setOrderId(orderId);
        request.setClientId(clientId);
        request.setItems(items);
        request.setTimestamp(String.valueOf(Instant.now().getEpochSecond()));
        request.setNonce(UUID.randomUUID().toString().replace("-", ""));

        // Compute HMAC over all order parameters
        String canonical = HmacUtil.buildCanonicalString(request);
        String hmac = HmacUtil.computeHmac(canonical, clientSecret);
        request.setHmacSignature(hmac);

        return request;
    }
}

