                "&status=" + response.getStatus() +
                "&totalPrice=" + response.getTotalPrice().toPlainString() +
                "&message=" + response.getMessage();
        boolean responseValid = HmacUtil.verifyHmac(responseCanonical, response.getResponseSignature(), clientSecret);
        System.out.println("Response signature valid: " + responseValid);

        // Demo: Tampered request
        System.out.println("\n=== Demo: Tampered Request (price changed) ===\n");
        OrderRequest tamperedRequest = OrderRequestBuilder.buildSignedRequest(
                "ORD-2024-002", clientId, clientSecret, items);
        // Attacker modifies price after signing
        tamperedRequest.getItems().get(0).setUnitPrice(new BigDecimal("0.01"));

        OrderResponse tamperedResponse = service.processOrder(tamperedRequest);
        System.out.println("Status: " + tamperedResponse.getStatus());
        System.out.println("Message: " + tamperedResponse.getMessage());

        // Demo: Replay attack
        System.out.println("\n=== Demo: Replay Attack (same nonce reused) ===\n");
        OrderRequest replayRequest = OrderRequestBuilder.buildSignedRequest(
                "ORD-2024-003", clientId, clientSecret, items);
        // First submission
        OrderResponse firstResponse = service.processOrder(replayRequest);
        System.out.println("First submission - Status: " + firstResponse.getStatus());
        // Replay
        OrderResponse replayResponse = service.processOrder(replayRequest);
        System.out.println("Replay attempt - Status: " + replayResponse.getStatus());
        System.out.println("Replay attempt - Message: " + replayResponse.getMessage());
